async SetTwoStepMulti( isActive: boolean, type: number )
{
    let dontClose = false;
    if ( tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }

    this.m_isTwoStepBlock = false;
    if ( isActive && !newBottombarManager.CheckExtraBetMaxBet( type ) )
    {
        msgBoxManager.ShowMessageBox( Define.StringKey.MSGBOX_BET_LIMIT_1 );
        isActive = false;
        dontClose = true;
        this.m_isTwoStepBlock = true;
    }
    if ( this.m_isTwoStep && this.m_toStepTwo )
    {
        if ( isActive )
        {
            newBottombarManager.ChangeMultiBet( type );
        }
        else if ( !dontClose ) // 取消開啟，要把第一階段開啟的動畫關掉
        {
            this.m_isExtra = false;
            if ( this.m_multiBtn_on.length == 1 )
            {
                this.m_multiBtn_on[ 0 ].node.active = false;
                this.m_multiBtn_off[ 0 ].node.active = true;
            }
            this.m_ExtraBetAniPlaying = true;
            newBottombarManager?.SetSpinState( SlotBottomBarState.CLICK_SPIN );
            if ( this.m_multiExtraBetNode )
            {
                await this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_OFF" );
            }
            this.m_ExtraBetAniPlaying = false;
            newBottombarManager?.SetSpinState( SlotBottomBarState.IDLE );
        }
    }
}

async ForceSetExtraBet( isActive: boolean, type: number = TYPE.Special )
{
    if ( tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    this.m_usedForce = true;
    if ( isActive )
    {
        this.m_isForceExtraOnEnd = false;
        this.m_isExtra = true;
        if ( this.m_multiBtn_on.length == 1 )
        {
            this.m_multiBtn_on[ 0 ].node.active = true;
            this.m_multiBtn_off[ 0 ].node.active = false;
        }

        // if ( this.m_isTwoStep )
        // {
        //     this.m_toStepTwo = true;
        //     this.SetTwoStepMulti( isActive, type );
        // }
        // else
        // {
        newBottombarManager.ChangeMultiBet( type );
        // }
        await this.m_triggerCb( isActive, true );
        this.m_ExtraBetAniPlaying = true;
        await this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_Close" );
        if ( this.m_multiExtraBetNode )
        {
            this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
        }
